import React, { useState } from 'react';
import {
  CDropdown,
  CDropdownToggle,
  CDropdownMenu,
  CDropdownItem,
} from '@coreui/react';
import '@coreui/coreui/dist/css/coreui.min.css'; // ✅ Make sure this is imported

const ProfileDropdown = () => {
  const [visible, setVisible] = useState(false);

  const handleToggle = () => {
    setVisible((prev) => !prev);
  };

  return (
    <CDropdown
      visible={visible}
      onVisibleChange={setVisible}
      className="profile-dropdown"
    >
      <CDropdownToggle
        className="p-0 border-0 bg-transparent"
        caret={false}
        onClick={handleToggle}
      >
        <img
          src="https://ui-avatars.com/api/?name=Dheeraj+Khanna"
          alt="User"
          className="rounded-circle"
          width="36"
          height="36"
          style={{ objectFit: 'cover', cursor: 'pointer' }}
        />
      </CDropdownToggle>

      {/* ✅ Ensure the menu gets className="show" when visible */}
      <CDropdownMenu className={visible ? 'pt-0 show' : 'pt-0'}>
        <CDropdownItem href="#">Profile</CDropdownItem>
        <CDropdownItem href="#">Settings</CDropdownItem>
        <CDropdownItem href="#">Logout</CDropdownItem>
      </CDropdownMenu>
    </CDropdown>
  );
};

export default ProfileDropdown;
